import { useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import axios from "axios";
import "./Dashboard.css";

function DashboardPage({ setIsLogin }) {
  const navigate = useNavigate();
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState("Semua");
  const [categories, setCategories] = useState([]);
  const [cart, setCart] = useState([]);
  const [showCart, setShowCart] = useState(false);
  const [error, setError] = useState("");
  const [user, setUser] = useState(null);

  const API_BASE_URL = "http://localhost:3000";

  useEffect(() => {
    const userData = localStorage.getItem("user");
    if (userData) {
      setUser(JSON.parse(userData));
    }
  }, []);

  useEffect(() => {
    fetchProductsAndCategories();
  }, []);

  useEffect(() => {
    const savedCart = localStorage.getItem("cart");
    if (savedCart) {
      setCart(JSON.parse(savedCart));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem("cart", JSON.stringify(cart));
  }, [cart]);

  const fetchProductsAndCategories = async () => {
    setLoading(true);
    setError("");
    
    try {
      const token = localStorage.getItem("token");
      const config = token ? {
        headers: { Authorization: `Bearer ${token}` }
      } : {};

      // AMBIL PRODUCTS dengan JOIN ke categories
      const productsRes = await axios.get(`${API_BASE_URL}/products`, config);
      console.log("Products from DB:", productsRes.data);

      // AMBIL CATEGORIES
      const categoriesRes = await axios.get(`${API_BASE_URL}/categories`, config);
      console.log("Categories from DB:", categoriesRes.data);

      // Format Categories
      let categoriesData = [];
      if (Array.isArray(categoriesRes.data)) {
        categoriesData = categoriesRes.data;
      } else if (categoriesRes.data.data && Array.isArray(categoriesRes.data.data)) {
        categoriesData = categoriesRes.data.data;
      }

      const formattedCategories = categoriesData.map(item => ({
        id: item.id_category || item.id,
        name: item.name,
        icon: getCategoryIcon(item.name)
      }));

      setCategories([
        { id: 0, name: "Semua", icon: "📦" },
        ...formattedCategories
      ]);

      // Format Products
      let productsData = [];
      if (Array.isArray(productsRes.data)) {
        productsData = productsRes.data;
      } else if (productsRes.data.data && Array.isArray(productsRes.data.data)) {
        productsData = productsRes.data.data;
      } else if (productsRes.data.products && Array.isArray(productsRes.data.products)) {
        productsData = productsRes.data.products;
      }

      // 🔥 MAPPING produk dengan GAMBAR (PAKAI PICSUM)
      const formattedProducts = productsData.map((item, index) => {
        // Cari nama kategori dari category_id
        let categoryName = "Umum";
        if (item.category_id) {
          const foundCategory = formattedCategories.find(c => c.id === item.category_id);
          if (foundCategory) {
            categoryName = foundCategory.name;
          }
        } else if (item.category) {
          categoryName = item.category;
        }

       

        return {
          id: item.id_product || item.id,
          name: item.name,
          price: parseFloat(item.price) || 0,
          category: categoryName,
          category_id: item.category_id,
          rating: 4.5, // Default rating
          stock: parseInt(item.stock) || 0,
          description: item.description || "",
          image_url: imageUrl
        };
      });

      console.log("Formatted products with images:", formattedProducts);
      setProducts(formattedProducts);

    } catch (error) {
      console.error("Error fetching data:", error);
      setError("Gagal memuat data. Menggunakan data cadangan...");
      loadMockData();
    } finally {
      setLoading(false);
    }
  };

  // Fungsi untuk icon kategori
  const getCategoryIcon = (categoryName) => {
    const iconMap = {
      'Laptop': '💻',
      'Smartphone': '📱',
      'Wearable': '⌚',
      'Aksesoris': '⌨️',
      'Televisi': '📺',
      'Peralatan Rumah': '🏠',
      'Kamera': '📷',
      'Drone': '🚁',
      'Audio': '🎧'
    };
    return iconMap[categoryName] || '📦';
  };

  // Mock data sebagai fallback (DENGAN GAMBAR PICSUM)
  const loadMockData = () => {
    const mockProducts = [
      { id: 1, name: "Laptop ASUS ROG Strix", price: 18500000, category: "Laptop", rating: 4.8, stock: 10, image_url: "data:image/jpeg;base64," },
      { id: 2, name: "Laptop Lenovo ThinkPad X1", price: 16500000, category: "Laptop", rating: 4.7, stock: 8, image_url: "https://tse1.mm.bing.net/th/id/OIP.EfZB3zdvE6jA998epUaQlwHaEK?pid=Api&P=0&h=180"},
      { id: 3, name: "Smartphone Samsung Galaxy S24", price: 12999000, category: "Smartphone", rating: 4.9, stock: 15, image_url: "data:image/jpeg;base64," },
      { id: 4, name: "Smartphone iPhone 15 Pro", price: 21999000, category: "Smartphone", rating: 4.9, stock: 12, image_url: "data:image/jpeg;base64," },
      { id: 5, name: "Smartwatch Xiaomi Watch 2", price: 2499000, category: "Wearable", rating: 4.5, stock: 25, image_url: "data:image/jpeg;base64," },
      { id: 6, name: "Headphone Sony WH-1000XM5", price: 5499000, category: "Aksesoris", rating: 4.8, stock: 20, image_url: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcT2j1n9DGSu0zh7Zr0HwseZKeQTjgPCwClTwQ&s" },
      { id: 7, name: "Smart TV LG 55 Inch 4K", price: 8499000, category: "Televisi", rating: 4.6, stock: 6, image_url: "https://tse3.mm.bing.net/th/id/OIP.0IT84wTsOHcCGaQVTzTeQAHaE6?pid=Api&P=0&h=180"},
      { id: 8, name: "Kulkas Samsung Inverter", price: 5999000, category: "Peralatan Rumah", rating: 4.7, stock: 5, image_url: "data:image/jpeg;base64," },
      { id: 9, name: "AC Daikin 1 PK Split", price: 5299000, category: "Peralatan Rumah", rating: 4.6, stock: 7, image_url: "data:image/jpeg;base64," },
      { id: 10, name: "Kamera Canon EOS M50", price: 8799000, category: "Kamera", rating: 4.8, stock: 9, image_url: "data:image/jpeg;base64," },
      { id: 11, name: "Drone DJI Mini 4", price: 11999000, category: "Drone", rating: 4.9, stock: 3, image_url: "data:image/jpeg;base64," },
      { id: 12, name: "Speaker JBL Charge 5", price: 2299000, category: "Audio", rating: 4.7, stock: 18, image_url: "data:image/jpeg;base64," },
      { id: 13, name: "Powerbank Anker 20000mAh", price: 899000, category: "Aksesoris", rating: 4.5, stock: 40, image_url: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSzaB1xODDTVBvghghmcWi8AezH43TfXOajtw&s" },
      { id: 14, name: "Mouse Logitech MX Master 3S", price: 1599000, category: "Aksesoris", rating: 4.8, stock: 25, image_url: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSVCK4tqBKS8dqDxWd7JhOamCxqvlKluVHWEQ&s" }
    ];

    const mockCategories = [
      { id: 0, name: "Semua", icon: "📦" },
      { id: 1, name: "Laptop", icon: "💻" },
      { id: 2, name: "Smartphone", icon: "📱" },
      { id: 3, name: "Wearable", icon: "⌚" },
      { id: 4, name: "Aksesoris", icon: "⌨️" },
      { id: 5, name: "Televisi", icon: "📺" },
      { id: 6, name: "Peralatan Rumah", icon: "🏠" },
      { id: 7, name: "Kamera", icon: "📷" },
      { id: 8, name: "Drone", icon: "🚁" },
      { id: 9, name: "Audio", icon: "🎧" }
    ];

    setProducts(mockProducts);
    setCategories(mockCategories);
  };

  const handleLogout = () => {
    localStorage.removeItem("isLogin");
    localStorage.removeItem("token");
    localStorage.removeItem("refreshToken");
    localStorage.removeItem("user");
    localStorage.removeItem("cart");
    setIsLogin(false);
    navigate("/login");
  };

  const handleBuy = (productId, productName) => {
    const productToBuy = products.find(p => p.id === productId);
    
    if (productToBuy.stock <= 0) {
      alert(`❌ Maaf, ${productName} sedang habis!`);
      return;
    }

    const updatedProducts = products.map(product => {
      if (product.id === productId) {
        return { ...product, stock: product.stock - 1 };
      }
      return product;
    });

    setProducts(updatedProducts);

    const existingItem = cart.find(item => item.id === productId);
    
    if (existingItem) {
      const updatedCart = cart.map(item =>
        item.id === productId
          ? { ...item, quantity: item.quantity + 1 }
          : item
      );
      setCart(updatedCart);
    } else {
      setCart([...cart, { 
        id: productId, 
        name: productName, 
        price: productToBuy.price,
        quantity: 1 
      }]);
    }

    alert(`✅ ${productName} berhasil ditambahkan ke keranjang! Stok tersisa: ${productToBuy.stock - 1}`);
  };

  const handleRemoveFromCart = (productId) => {
    const cartItem = cart.find(item => item.id === productId);
    
    const updatedProducts = products.map(product => {
      if (product.id === productId) {
        return { ...product, stock: product.stock + cartItem.quantity };
      }
      return product;
    });
    setProducts(updatedProducts);

    const updatedCart = cart.filter(item => item.id !== productId);
    setCart(updatedCart);
  };

  const handleCheckout = () => {
    if (cart.length === 0) {
      alert("Keranjang belanja masih kosong!");
      return;
    }

    const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    alert(`✅ Checkout berhasil!\nTotal pembayaran: Rp ${total.toLocaleString()}\nTerima kasih telah berbelanja!`);
    
    setCart([]);
  };

  // Filter produk berdasarkan kategori yang dipilih
  const filteredProducts = selectedCategory === "Semua" 
    ? products 
    : products.filter(product => product.category === selectedCategory);

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const cartItemCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  // Format harga tanpa desimal
  const formatPrice = (price) => {
    return `Rp ${Math.round(price).toLocaleString('id-ID')}`;
  };

  return (
    <div className="dashboard-container">
      {/* HEADER */}
      <div className="dashboard-header">
        <div>
          <h1>🛍️ Toko Elektronik Digital</h1>
          <p>Jelajahi produk elektronik terbaik berdasarkan kategori</p>
          {user && (
            <p style={{ fontSize: '14px', color: '#3b82f6', marginTop: '5px' }}>
              👋 Selamat datang, {user.name || user.username}
            </p>
          )}
        </div>
        <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
          <button 
            onClick={() => setShowCart(!showCart)}
            style={{
              background: '#3b82f6',
              color: 'white',
              border: 'none',
              padding: '10px 20px',
              borderRadius: '10px',
              cursor: 'pointer',
              display: 'flex',
              alignItems: 'center',
              gap: '5px',
              position: 'relative'
            }}
          >
            🛒 Keranjang
            {cartItemCount > 0 && (
              <span style={{
                background: '#ef4444',
                color: 'white',
                borderRadius: '50%',
                padding: '2px 8px',
                fontSize: '12px',
                marginLeft: '5px'
              }}>
                {cartItemCount}
              </span>
            )}
          </button>
          <button onClick={handleLogout} className="logout-btn">🔓 Logout</button>
        </div>
      </div>

      {/* CART MODAL */}
      {showCart && (
        <div style={{
          position: 'fixed',
          top: '50%',
          left: '50%',
          transform: 'translate(-50%, -50%)',
          background: 'white',
          padding: '25px',
          borderRadius: '20px',
          boxShadow: '0 20px 60px rgba(0,0,0,0.3)',
          zIndex: 1000,
          maxWidth: '500px',
          width: '90%',
          maxHeight: '80vh',
          minWidth : '120 px',
          justifyContent: 'center',
          overflowY: 'auto'
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
            <h2 style={{ color: '#1e40af', margin: 0 }}>🛒 Keranjang Belanja</h2>
            <button 
              onClick={() => setShowCart(false)}
              style={{
                background: 'none',
                border: 'none',
                fontSize: '24px',
                cursor: 'pointer',
                color: '#666'
              }}
            >
              ✕
            </button>
          </div>

          {cart.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '30px', color: '#666' }}>
              <div style={{ fontSize: '48px', marginBottom: '10px' }}>🛒</div>
              <p>Keranjang belanja masih kosong</p>
            </div>
          ) : (
            <>
              {cart.map(item => (
                <div key={item.id} style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  padding: '15px',
                  borderBottom: '1px solid #e5e7eb',
                  gap: '10px'
                }}>
                  <div style={{ flex: 1 }}>
                    <h4 style={{ margin: '0 0 5px 0' }}>{item.name}</h4>
                    <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                      <span style={{ color: '#3b82f6', fontWeight: 'bold' }}>
                        {formatPrice(item.price * item.quantity)}
                      </span>
                      <span style={{ color: '#666', fontSize: '14px' }}>
                        ({formatPrice(item.price)} x {item.quantity})
                      </span>
                    </div>
                  </div>
                  <button
                    onClick={() => handleRemoveFromCart(item.id)}
                    style={{
                      background: '#ef4444',
                      color: 'white',
                      border: 'none',
                      padding: '5px 10px',
                      borderRadius: '5px',
                      cursor: 'pointer',
                      fontSize: '12px'
                    }}
                  >
                    ✕ Hapus
                  </button>
                </div>
              ))}

              <div style={{
                marginTop: '20px',
                padding: '15px',
                background: '#f3f4f6',
                borderRadius: '10px'
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 'bold' }}>
                  <span>Total:</span>
                  <span style={{ color: '#3b82f6' }}>{formatPrice(cartTotal)}</span>
                </div>
              </div>

              <button
                onClick={handleCheckout}
                style={{
                  width: '100%',
                  padding: '15px',
                  marginTop: '20px',
                  background: 'linear-gradient(135deg, #4cc9f0 0%, #4361ee 100%)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '10px',
                  cursor: 'pointer',
                  fontWeight: 'bold',
                  fontSize: '16px'
                }}
              >
                ✅ Checkout
              </button>
            </>
          )}
        </div>
      )}

      {/* CATEGORY FILTER */}
      <div className="category-filter">
        <h2>📋 Kategori Produk</h2>
        <div className="category-buttons">
          {categories.map(category => (
            <button
              key={category.id}
              className={`category-btn ${selectedCategory === category.name ? 'active' : ''}`}
              onClick={() => setSelectedCategory(category.name)}
            >
              <span className="category-icon">{category.icon}</span>
              <span className="category-name">{category.name}</span>
            </button>
          ))}
        </div>
      </div>

      {/* PRODUCT SECTION */}
      <div className="product-section">
        <div className="section-header">
          <h2>
            {selectedCategory === "Semua" ? "📦 Semua Produk" : `${getCategoryIcon(selectedCategory)} ${selectedCategory}`}
            <span className="product-count"> ({filteredProducts.length} produk)</span>
          </h2>
        </div>

        {/* PRODUCT LIST DENGAN GAMBAR */}
        <div className="product-list">
          {loading ? (
            <div className="loading">
              <div className="spinner">⏳</div>
              <p>Memuat produk dari database...</p>
            </div>
          ) : filteredProducts.length === 0 ? (
            <div className="empty-state">
              <div className="empty-icon">📭</div>
              <p>Tidak ada produk dalam kategori ini</p>
            </div>
          ) : (
            filteredProducts.map((item) => (
              <div key={item.id} className="product-card">
                {/* GAMBAR PRODUK */}
                <div className="product-image-container">
                  <img 
                    src={item.image_url} 
                    alt={item.name}
                    className="product-image"
                    onError={(e) => {
                      e.target.onerror = null;
                      e.target.src = 'https://picsum.photos/200/200';
                    }}
                  />
                </div>

                <div className="product-info">
                  <h3>{item.name}</h3>
                  <div className="product-meta">
                    <span className="category-badge">{item.category}</span>
                    <div className="rating">
                      {"★".repeat(Math.floor(item.rating))}
                      {"☆".repeat(5 - Math.floor(item.rating))}
                      <span className="rating-number">({item.rating})</span>
                    </div>
                  </div>
                  <p className="price">{formatPrice(item.price)}</p>
                  
                  {/* TAMPILAN STOK */}
                  <div className={`stock-badge ${item.stock === 0 ? 'habis' : item.stock > 10 ? 'banyak' : 'sedikit'}`}>
                    Stok: {item.stock} {item.stock === 0 && '❌ Habis'}
                  </div>
                </div>

                <button 
                  onClick={() => handleBuy(item.id, item.name)}
                  className="buy-btn"
                  disabled={item.stock === 0}
                >
                  🛒 {item.stock === 0 ? 'Stok Habis' : 'Beli'}
                </button>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

export default DashboardPage;